function ChatView({ messages, isStreaming, streamingMessageId, onSendPrompt, pendingUiRequests, respondToUiRequest, onForkAtEntry, getForkMessages, forkPoints, viewMode }: ChatViewProps): React.ReactElement {
  const bottomRef = useRef<HTMLDivElement>(null)
  const [annotatingTarget, setAnnotatingTarget] = useState<{
    messageId: string
    blockIndex: number
  } | null>(null)
  const [forkInputMessageId, setForkInputMessageId] = useState<string | null>(null)
  const [forkEntryId, setForkEntryId] = useState<string | null>(null)
  const [expandedTurns, setExpandedTurns] = useState<Set<string>>(new Set())

  const handleEnterAnnotation = useCallback((messageId: string, blockIndex: number) => {
    setAnnotatingTarget({ messageId, blockIndex })
  }, [])

  const handleExitAnnotation = useCallback(() => {
    setAnnotatingTarget(null)
  }, [])

  const handleSendFeedback = useCallback(
    (description: string, imageData: string) => {
      onSendPrompt(description, [{ data: imageData, mimeType: 'image/png' }])
      setAnnotatingTarget(null)
    },
    [onSendPrompt],
  )

  const handleForkClick = useCallback(async (messageId: string, piEntryId: string | undefined) => {
    if (forkInputMessageId === messageId) {
      setForkInputMessageId(null)
      setForkEntryId(null)
      return
    }
    if (piEntryId) {
      setForkEntryId(piEntryId)
    } else {
      const msgs = await getForkMessages()
      const lastMsg = msgs[msgs.length - 1]
      setForkEntryId(lastMsg?.entryId ?? null)
    }
    setForkInputMessageId(messageId)
  }, [forkInputMessageId, getForkMessages])

  const toggleTurn = useCallback((turnId: string) => {
    setExpandedTurns((prev) => {
      const next = new Set(prev)
      if (next.has(turnId)) {
        next.delete(turnId)
      } else {
        next.add(turnId)
      }
      return next
    })
  }, [])

  const handleForkClose = useCallback(() => {
    setForkInputMessageId(null)
    setForkEntryId(null)
  }, [])

  // Throttled scroll: only scroll on animation frames to avoid jank
  const scrollRafRef = useRef<number | null>(null)
  useEffect(() => {
    if (scrollRafRef.current !== null) cancelAnimationFrame(scrollRafRef.current)
    scrollRafRef.current = requestAnimationFrame(() => {
      scrollRafRef.current = null
      bottomRef.current?.scrollIntoView({ behavior: isStreaming ? 'auto' : 'smooth' })
    })
    return () => {
      if (scrollRafRef.current !== null) cancelAnimationFrame(scrollRafRef.current)
    }
  }, [messages, isStreaming])

  const turns = viewMode !== 'normal' ? groupByTurns(messages) : []

  return (
    <div className="flex-1 overflow-y-auto bg-white px-4 py-6">
      {messages.length === 0 ? (
        <div className="flex h-full items-center justify-center">
          <div className="text-center">
            <p className="text-lg text-gray-400">Start a conversation with Pi</p>
            <p className="mt-2 text-sm text-gray-400">Type a message below or connect to Pi first</p>
          </div>
        </div>
      ) : viewMode === 'normal' ? (
        <div className="mx-auto max-w-3xl space-y-4">
          {(() => {
            // Merge consecutive assistant messages into one card
            const groups: { role: 'user' | 'assistant'; msgs: ChatMessage[] }[] = []
            for (const msg of messages) {
              if (msg.role === 'system') continue
              const last = groups[groups.length - 1]
              if (last && last.role === msg.role) {
                last.msgs.push(msg)
              } else {
                groups.push({ role: msg.role as 'user' | 'assistant', msgs: [msg] })
              }
            }

            return groups.map((group, gi) => {
              const isUser = group.role === 'user'
              const allBlocks = group.msgs.flatMap((m) => m.blocks)
              // Use the first message's id for fork targeting
              const firstMsg = group.msgs[0]
              const msgForkPoints = forkPoints.filter((fp) => group.msgs.some((m) => m.piEntryId === fp.entryId))

              return (
                <div
                  key={gi}
                  className={`group relative rounded-lg px-4 py-3 ${
                    isUser ? 'bg-blue-50' : 'bg-gray-50'
                  }`}
                >
                  <div className="mb-1 flex items-center justify-between">
                    <span className="text-xs font-medium text-gray-500">
                      {isUser ? 'You' : 'Pi'}
                    </span>
                    <div className="relative flex items-center gap-1">
                      <CopyButton blocks={allBlocks} />
                      <button
                        onClick={() => handleForkClick(firstMsg.id, firstMsg.piEntryId)}
                        className="rounded px-2 py-0.5 text-xs text-gray-400 opacity-0 transition-opacity hover:text-gray-600 hover:bg-gray-100 group-hover:opacity-100"
                      >
                        Fork
                      </button>
                      {forkInputMessageId === firstMsg.id && forkEntryId && (
                        <ForkNameInput
                          onForkAtEntry={onForkAtEntry}
                          onClose={() => { setForkInputMessageId(null); setForkEntryId(null) }}
                          defaultEntryId={forkEntryId}
                        />
                      )}
                    </div>
                  </div>
                  <MergedBlocksRenderer
                    messages={group.msgs}
                    isStreaming={isStreaming}
                    streamingMessageId={streamingMessageId}
                    annotatingTarget={annotatingTarget}
                    onEnterAnnotation={handleEnterAnnotation}
                    onExitAnnotation={handleExitAnnotation}
                    onSendFeedback={handleSendFeedback}
                  />
                  {msgForkPoints.length > 0 && (
                    <div className="mt-2 flex flex-wrap gap-1.5 border-t border-gray-200/50 pt-2">
                      {msgForkPoints.map((fp, idx) => (
                        <span
                          key={idx}
                          className="inline-flex items-center gap-1 rounded-full bg-purple-100 px-2 py-0.5 text-[10px] text-purple-700"
                        >
                          <svg className="w-3 h-3" fill="none" viewBox="0 0 24 24" stroke="currentColor" strokeWidth={2}>
                            <path strokeLinecap="round" strokeLinejoin="round" d="M13 17h8m0 0V9m0 8l-8-8-4 4-6-6" />
                          </svg>
                          forked: {fp.childName || '(unnamed)'}
                        </span>
                      ))}
                    </div>
                  )}
                </div>
              )
            })
          })()}
          <div ref={bottomRef} />
        </div>
      ) : viewMode === 'turn' ? (
        <div className="mx-auto max-w-3xl space-y-0">
          {turns.map((turn, idx) => (
            <TurnCard
              key={turn.id}
              turn={turn}
              isFirst={idx === 0}
              isLast={idx === turns.length - 1}
              isExpanded={expandedTurns.has(turn.id)}
              onToggleExpand={() => toggleTurn(turn.id)}
              annotatingTarget={annotatingTarget}
              onEnterAnnotation={handleEnterAnnotation}
              onExitAnnotation={handleExitAnnotation}
              onSendFeedback={handleSendFeedback}
              onForkClick={handleForkClick}
              forkInputMessageId={forkInputMessageId}
              forkEntryId={forkEntryId}
              onForkClose={handleForkClose}
              onForkAtEntry={onForkAtEntry}
              forkPoints={forkPoints}
              isStreaming={isStreaming}
              streamingMessageId={streamingMessageId}
            />
          ))}
          <div ref={bottomRef} />
        </div>
      ) : (
        <div className="mx-auto max-w-3xl space-y-0">
          {turns.map((turn, idx) => (
            <OutlineRow
              key={turn.id}
              turn={turn}
              isFirst={idx === 0}
              isLast={idx === turns.length - 1}
              isExpanded={expandedTurns.has(turn.id)}
              onToggleExpand={() => toggleTurn(turn.id)}
              annotatingTarget={annotatingTarget}
              onEnterAnnotation={handleEnterAnnotation}
              onExitAnnotation={handleExitAnnotation}
              onSendFeedback={handleSendFeedback}
              onForkClick={handleForkClick}
              forkInputMessageId={forkInputMessageId}
              forkEntryId={forkEntryId}
              onForkClose={handleForkClose}
              onForkAtEntry={onForkAtEntry}
              forkPoints={forkPoints}
              isStreaming={isStreaming}
              streamingMessageId={streamingMessageId}
            />
          ))}
          <div ref={bottomRef} />
        </div>
      )}
    </div>
  )
}

export default ChatView

import { useEffect, useState, useCallback, useRef } from 'react'
import { usePiRpc } from './hooks/usePiRpc'
import { useSessionManager } from './hooks/useSessionManager'
import ChatView from './components/ChatView'
import InputBar from './components/InputBar'
import SessionSidebar from './components/SessionSidebar'
import { TokenUsageRing } from './components/TokenUsageRing'
import type { ViewMode } from './utils/compact-view'

function getDisplayName(session: { name: string | null; createdAt: string }): string {
  if (session.name) return session.name
  const d = new Date(session.createdAt)
  const month = d.toLocaleString('en', { month: 'short' })
  const day = d.getDate()
  const hh = String(d.getHours()).padStart(2, '0')
  const mm = String(d.getMinutes()).padStart(2, '0')
  return `${month} ${day} ${hh}:${mm}`
}

function App(): React.ReactElement {
  const { messages, isConnected, isStreaming, streamingMessageId, sendPrompt, abort, pendingUiRequests, respondToUiRequest, clearMessages, loadHistory, forkPoints, loadForkPoints, setOnAgentEnd, tokenUsage } = usePiRpc()
  const { sessions, currentSession, forkAtEntry, switchSession, newSession, renameSession, deleteSession, setSessionStatus, getForkMessages, clearSession, refresh } = useSessionManager(isConnected)
  const [error, setError] = useState<string | null>(null)
  const [sidebarCollapsed, setSidebarCollapsed] = useState(() => {
    const saved = localStorage.getItem('xi-sidebar-collapsed')
    return saved === 'true'
  })
  const [sidebarWidth, setSidebarWidth] = useState(() => {
    const saved = localStorage.getItem('xi-sidebar-width')
    const parsed = saved ? parseInt(saved, 10) : 260
    return Number.isNaN(parsed) ? 260 : Math.min(480, Math.max(180, parsed))
  })
  const [isResizing, setIsResizing] = useState(false)
  const sidebarWidthRef = useRef(sidebarWidth)
  sidebarWidthRef.current = sidebarWidth
  const resizeStartRef = useRef<{ startX: number; startWidth: number } | null>(null)

  useEffect(() => {
    if (!isResizing) return
    const handleMouseMove = (e: MouseEvent) => {
      if (!resizeStartRef.current) return
      const delta = e.clientX - resizeStartRef.current.startX
      const newWidth = Math.min(480, Math.max(180, resizeStartRef.current.startWidth + delta))
      setSidebarWidth(newWidth)
    }
    const handleMouseUp = () => {
      setIsResizing(false)
      resizeStartRef.current = null
      localStorage.setItem('xi-sidebar-width', String(sidebarWidthRef.current))
      document.body.style.cursor = ''
      document.body.style.userSelect = ''
    }
    document.body.style.cursor = 'col-resize'
    document.body.style.userSelect = 'none'
    window.addEventListener('mousemove', handleMouseMove)
    window.addEventListener('mouseup', handleMouseUp)
    return () => {
      window.removeEventListener('mousemove', handleMouseMove)
      window.removeEventListener('mouseup', handleMouseUp)
    }
  }, [isResizing])

  const handleResizeStart = useCallback((e: React.MouseEvent) => {
    e.preventDefault()
    setIsResizing(true)
    resizeStartRef.current = { startX: e.clientX, startWidth: sidebarWidth }
  }, [sidebarWidth])
  const [activeSessionPath, setActiveSessionPath] = useState<string | null>(null)
  const [viewMode, setViewMode] = useState<ViewMode>(() => {
    const saved = localStorage.getItem('xi-view-mode') as ViewMode
    return saved === 'normal' || saved === 'turn' || saved === 'outline' ? saved : 'normal'
  })

  const activeSession = activeSessionPath
    ? sessions?.projects?.flatMap(p => p.allSessions).find(s => s.filePath === activeSessionPath)
    : currentSession

  const activeSessionName = activeSession ? getDisplayName(activeSession) : null

  async function handleConnect(): Promise<void> {
    setError(null)
    const result = await window.api.start()
    if (!result.ok && result.error) {
      setError(result.error)
    }
    refresh()
  }

  // Auto-start Pi on mount
  useEffect(() => {
    handleConnect()
  }, [])

  const handleSwitchSession = useCallback(async (sessionPath: string) => {
    const prevPath = activeSessionPath
    setActiveSessionPath(sessionPath)
    const result = await switchSession(sessionPath)
    if (result.success) {
      clearMessages()
      await loadHistory()
      await loadForkPoints(sessionPath)
      await refresh()
    } else {
      setActiveSessionPath(prevPath)
    }
  }, [activeSessionPath, clearMessages, switchSession, loadHistory, loadForkPoints, refresh])

  const handleNewSession = useCallback(async (name: string, parentSessionPath: string) => {
    clearMessages()
    const result = await newSession(name, parentSessionPath)
    if (result) await refresh()
  }, [clearMessages, newSession, refresh])

  const handleForkAtEntry = useCallback(async (entryId: string, name: string) => {
    clearMessages()
    await forkAtEntry(entryId, name)
    await loadHistory()
    await refresh()
  }, [clearMessages, forkAtEntry, loadHistory, refresh])

  const handleForkFromEnd = useCallback(async (sessionPath: string, name: string) => {
    const msgs = await getForkMessages()
    const lastEntry = msgs[msgs.length - 1]
    if (!lastEntry?.entryId) return
    clearMessages()
    await forkAtEntry(lastEntry.entryId, name)
    await loadHistory()
    await refresh()
    setActiveSessionPath(null)
  }, [getForkMessages, clearMessages, forkAtEntry, loadHistory, refresh, setActiveSessionPath])

  const handleClearSession = useCallback(async () => {
    clearMessages()
    const ok = await clearSession()
    if (ok) {
      clearMessages()
      await loadHistory()
      await refresh()
      setActiveSessionPath(null)
    }
  }, [clearMessages, clearSession, loadHistory, refresh])

  useEffect(() => {
    if (isConnected) {
      loadHistory()
    }
  }, [isConnected, loadHistory])

  useEffect(() => {
    if (isConnected && currentSession?.filePath) {
      loadForkPoints(currentSession.filePath)
    }
  }, [isConnected, currentSession?.filePath, loadForkPoints])

  useEffect(() => {
    setOnAgentEnd(() => refresh)
  }, [setOnAgentEnd, refresh])

  useEffect(() => {
    function handleKeyDown(e: KeyboardEvent): void {
      if (e.key === 'Escape' && isStreaming) {
        abort()
      }
    }
    window.addEventListener('keydown', handleKeyDown)
    return () => window.removeEventListener('keydown', handleKeyDown)
  }, [isStreaming, abort])

  useEffect(() => {
    const cleanup = window.api.onEvent((rawEvent) => {
      const evt = rawEvent as { type: string; error?: string; errorMessage?: string }
      if (evt.type === 'extension_error' && evt.error) {
        setError(`Extension error: ${evt.error}`)
      }
    })
    return cleanup
  }, [])

  const projects = sessions?.projects ?? []
  const projectName = projects[0]?.projectPath.split('/').pop() ?? 'Sessions'
  const collapsedSidebarWidth = 48
  const currentSidebarWidth = sidebarCollapsed ? collapsedSidebarWidth : sidebarWidth

  return (
    <div className="flex flex-col h-screen w-screen overflow-hidden bg-white text-gray-900">
      {/* Unified header row split at sidebar width */}
      <div className="flex border-b border-gray-200 bg-gray-50" style={{ WebkitAppRegion: 'drag' } as React.CSSProperties}>
        {/* Left: sidebar header zone */}
        <div
          className="flex items-center justify-between px-3 pt-10 pb-2 flex-shrink-0"
          style={{ width: currentSidebarWidth }}
        >
          <span className="text-xs font-semibold uppercase tracking-wider text-gray-500 truncate">{sidebarCollapsed ? '' : projectName}</span>
          <button
            onClick={() => {
              const next = !sidebarCollapsed
              setSidebarCollapsed(next)
              localStorage.setItem('xi-sidebar-collapsed', String(next))
            }}
            className="rounded p-1 text-gray-500 hover:text-gray-700 hover:bg-gray-100 transition-colors"
            title={sidebarCollapsed ? 'Show sessions' : 'Hide sessions'}
            style={{ WebkitAppRegion: 'no-drag' } as React.CSSProperties}
          >
            <svg className="w-4 h-4" fill="none" viewBox="0 0 24 24" stroke="currentColor" strokeWidth={2}>
              {sidebarCollapsed ? (
                <path strokeLinecap="round" strokeLinejoin="round" d="M13 5l7 7-7 7M5 5l7 7-7 7" />
              ) : (
                <path strokeLinecap="round" strokeLinejoin="round" d="M11 19l-7-7 7-7M19 19l-7-7 7-7" />
              )}
            </svg>
          </button>
        </div>
        {/* Right: main header zone */}
        <div className="flex items-center justify-between flex-1 px-4 pt-10 pb-2 min-w-0">
          <div className="flex items-center gap-2" style={{ WebkitAppRegion: 'no-drag' } as React.CSSProperties}>
            {activeSessionName && (
              <>
                <span className="text-xs text-gray-700 font-medium">
                  {activeSessionName}
                </span>
                <button
                  onClick={handleClearSession}
                  className="rounded p-1 text-gray-400 hover:text-red-500 hover:bg-gray-100 transition-colors"
                  title="Clear conversation"
                >
                  <svg className="w-3.5 h-3.5" fill="none" viewBox="0 0 24 24" stroke="currentColor" strokeWidth={2}>
                    <path strokeLinecap="round" strokeLinejoin="round" d="M19 7l-.867 12.142A2 2 0 0116.138 21H7.862a2 2 0 01-1.995-1.858L5 7m5 4v6m4-6v6m1-10V4a1 1 0 00-1-1h-4a1 1 0 00-1 1v3M4 7h16" />
                  </svg>
                </button>
              </>
            )}

            {error && (
              <span className="text-xs text-red-500" title={error}>Error</span>
            )}
          </div>
          <div style={{ WebkitAppRegion: 'no-drag' } as React.CSSProperties}>
            <TokenUsageRing
              usedTokens={tokenUsage.totalTokens}
              contextWindowSize={tokenUsage.contextWindowSize}
              inputTokens={tokenUsage.inputTokens}
              outputTokens={tokenUsage.outputTokens}
              cacheReadTokens={tokenUsage.cacheReadTokens}
              totalCost={tokenUsage.totalCost}
            />
          </div>
          <div className="flex items-center rounded-md border border-gray-200 bg-gray-100 p-0.5" style={{ WebkitAppRegion: 'no-drag' } as React.CSSProperties}>
            <button
              onClick={() => { localStorage.setItem('xi-view-mode', 'normal'); setViewMode('normal') }}
              className={`rounded px-2 py-0.5 text-xs font-medium transition-colors ${viewMode === 'normal' ? 'bg-gray-200 text-gray-900 shadow-sm' : 'text-gray-500 hover:text-gray-700'}`}
              title="Full view"
            >
              <svg className="w-3.5 h-3.5" fill="none" viewBox="0 0 24 24" stroke="currentColor" strokeWidth={2}>
                <path strokeLinecap="round" strokeLinejoin="round" d="M3 4h18M3 8h18M3 12h18M3 16h18M3 20h18" />
              </svg>
            </button>
            <button
              onClick={() => { localStorage.setItem('xi-view-mode', 'turn'); setViewMode('turn') }}
              className={`rounded px-2 py-0.5 text-xs font-medium transition-colors ${viewMode === 'turn' ? 'bg-gray-200 text-gray-900 shadow-sm' : 'text-gray-500 hover:text-gray-700'}`}
              title="Turn view"
            >
              <svg className="w-3.5 h-3.5" fill="none" viewBox="0 0 24 24" stroke="currentColor" strokeWidth={2}>
                <path strokeLinecap="round" strokeLinejoin="round" d="M3 5h18M6 9h12M3 13h18M6 17h12" />
              </svg>
            </button>
            <button
              onClick={() => { localStorage.setItem('xi-view-mode', 'outline'); setViewMode('outline') }}
              className={`rounded px-2 py-0.5 text-xs font-medium transition-colors ${viewMode === 'outline' ? 'bg-gray-200 text-gray-900 shadow-sm' : 'text-gray-500 hover:text-gray-700'}`}
              title="Outline view"
            >
              <svg className="w-3.5 h-3.5" fill="none" viewBox="0 0 24 24" stroke="currentColor" strokeWidth={2}>
                <path strokeLinecap="round" strokeLinejoin="round" d="M3 7h18M3 12h18M3 17h18" />
              </svg>
            </button>
          </div>
          <div className="flex items-center gap-2" style={{ WebkitAppRegion: 'no-drag' } as React.CSSProperties}>
            {!isConnected && (
              <button
                onClick={handleConnect}
                className="rounded bg-blue-600 px-3 py-1 text-xs font-medium text-white hover:bg-blue-500"
              >
                Connect to Pi
              </button>
            )}
          </div>
        </div>
      </div>

      {/* Body: sidebar + main content */}
      <div className="flex flex-1 overflow-hidden">
        <SessionSidebar
          sessions={sessions}
          currentSession={currentSession}
          onSwitchSession={handleSwitchSession}
          onNewSession={handleNewSession}
          onRenameSession={renameSession}
          onDeleteSession={deleteSession}
          onSetSessionStatus={setSessionStatus}
          onForkFromEnd={handleForkFromEnd}
          isCollapsed={sidebarCollapsed}
          onToggleCollapse={() => {
            const next = !sidebarCollapsed
            setSidebarCollapsed(next)
            localStorage.setItem('xi-sidebar-collapsed', String(next))
          }}
          width={sidebarWidth}
          onResizeStart={handleResizeStart}
        />

        <div className="flex flex-1 flex-col overflow-hidden">
          <ChatView
            messages={messages}
            isStreaming={isStreaming}
            streamingMessageId={streamingMessageId}
            pendingUiRequests={pendingUiRequests}
            respondToUiRequest={respondToUiRequest}
            onSendPrompt={sendPrompt}
            onForkAtEntry={handleForkAtEntry}
            getForkMessages={getForkMessages}
            forkPoints={forkPoints}
            viewMode={viewMode}
          />

          <InputBar onSend={sendPrompt} disabled={!isConnected || isStreaming} isConnected={isConnected} isStreaming={isStreaming} onStop={isStreaming ? abort : undefined} />
        </div>
      </div>
    </div>
  )
}

export default App

import { readdirSync, readFileSync, existsSync, appendFileSync, unlinkSync, rmSync } from 'fs'
import { join, dirname, resolve } from 'path'
import type {
  SessionInfo,
  SessionListResult,
  SessionFileHeader,
  ProjectSessionTree,
  SessionTreeNode,
  ForkPoint
} from '../renderer/src/types/session'

export function getSessionDir(cwd?: string): string {
  const projectRoot = cwd ?? process.cwd()
  const resolvedCwd = resolve(projectRoot)
  const agentDir = join(resolvedCwd, '.xi')
  const safePath = `--${resolvedCwd.replace(/^[/\\]/, '').replace(/[/\\:]/g, '-')}--`
  const sessionDir = join(agentDir, 'sessions', safePath)
  if (!existsSync(sessionDir)) {
    mkdirSync(sessionDir, { recursive: true })
  }
  return sessionDir
}


export function parseSessionFile(filePath: string): SessionInfo | null {
  try {
    const content = readFileSync(filePath, 'utf-8')
    const lines = content.split('\n').filter((line) => line.trim().length > 0)
    if (lines.length === 0) return null

    let header: SessionFileHeader
    try {
      header = JSON.parse(lines[0]) as SessionFileHeader
    } catch {
      return null
    }

    if (header.type !== 'session') return null

    let messageCount = 0
    let name: string | null = null
    let status: 'active' | 'completed' | null = null

    for (let i = 1; i < lines.length; i++) {
      try {
        const entry = JSON.parse(lines[i]) as Record<string, unknown>
        if (entry.type === 'message') {
          const message = entry.message as Record<string, unknown> | undefined
          if (message && message.role === 'user') {
            messageCount++
          }
        } else if (entry.type === 'session_info') {
          if (typeof entry.name === 'string') {
            name = entry.name
          }
          if (entry.status === 'active' || entry.status === 'completed') {
            status = entry.status
          }
        }
      } catch {
        continue
      }
    }

    return {
      filePath,
      sessionId: header.id,
      name,
      status,
      createdAt: header.timestamp,
      cwd: header.cwd,
      parentSessionPath: header.parentSession ?? null,
      messageCount,
      isMain: false
    }
  } catch {
    return null
  }
}

export function findMainSession(cwd: string, sessionDir?: string): SessionInfo | null {
  const dir = sessionDir ?? getSessionDir()
  if (!existsSync(dir)) return null

  const sessionFiles = readdirSync(dir)
    .filter((name) => name.endsWith('.jsonl'))
    .map((name) => join(dir, name))

  for (const filePath of sessionFiles) {
    const info = parseSessionFile(filePath)
    if (info && info.cwd === cwd && info.name === 'main') {
      return info
    }
  }

  const candidates: SessionInfo[] = []
  for (const filePath of sessionFiles) {
    const info = parseSessionFile(filePath)
    if (info && info.cwd === cwd) {
      candidates.push(info)
    }
  }
  if (candidates.length > 0) {
    candidates.sort((a, b) => a.createdAt.localeCompare(b.createdAt))
    return candidates[0]
  }

  return null
}

export function listSessions(_currentSessionPath?: string, sessionDir?: string): SessionListResult {
  const sessionDirPath = sessionDir ?? getSessionDir()
  if (!existsSync(sessionDirPath)) {
    return { projects: [] }
  }

  let sessionFiles: string[]
  try {
    sessionFiles = readdirSync(sessionDirPath)
      .filter((name) => name.endsWith('.jsonl'))
      .map((name) => join(sessionDirPath, name))
  } catch {
    return { projects: [] }
  }

  const sessions: SessionInfo[] = []
  for (const filePath of sessionFiles) {
    const info = parseSessionFile(filePath)
    if (info) sessions.push(info)
  }

  if (sessions.length === 0) {
    return { projects: [] }
  }

  sessions.sort((a, b) => a.createdAt.localeCompare(b.createdAt))

  const namedMain = sessions.find((s) => s.name === 'main')
  if (namedMain) {
    namedMain.isMain = true
  } else if (sessions.length > 0) {
    sessions[0].isMain = true
  }

  const cwd = sessions[0].cwd
  const tree = buildSessionTree(sessions)
  const encodedDir = sessionDirPath.split('/').pop() ?? ''

  const projects: ProjectSessionTree[] = [{
    projectPath: cwd,
    encodedDir,
    root: tree,
    allSessions: sessions
  }]

  return { projects }
}

export function buildSessionTree(sessions: SessionInfo[]): SessionTreeNode | null {
  if (sessions.length === 0) return null

  const nodeMap = new Map<string, SessionTreeNode>()
  const parentedNodes = new Set<string>()

  for (const session of sessions) {
    nodeMap.set(session.filePath, { session, children: [] })
  }

  for (const session of sessions) {
    if (session.parentSessionPath && nodeMap.has(session.parentSessionPath)) {
      const parent = nodeMap.get(session.parentSessionPath)!
      const node = nodeMap.get(session.filePath)!
      parent.children.push(node)
      parentedNodes.add(session.filePath)
    }
  }

  let root: SessionTreeNode | null = null

  const mainSession = sessions.find((s) => s.isMain)
  if (mainSession) {
    root = nodeMap.get(mainSession.filePath) ?? null
  }

  if (!root) {
    const orphan = sessions.find((s) => !parentedNodes.has(s.filePath))
    if (orphan) {
      root = nodeMap.get(orphan.filePath) ?? null
    }
  }

  if (!root && sessions.length > 0) {
    root = nodeMap.get(sessions[0].filePath) ?? null
  }

  if (root) {
    for (const session of sessions) {
      if (session.filePath === root.session.filePath) continue
      if (parentedNodes.has(session.filePath)) continue
      const node = nodeMap.get(session.filePath)!
      root.children.push(node)
    }
  }

  return root
}

export function nameSession(sessionPath: string, name: string, _cwd?: string, _parentSessionPath?: string): boolean {
  try {
    // Only append session_info if the file already exists on disk.
    // For new sessions, the Pi worker's flush_session command handles
    // creating the file with the correct header (including parentSession).
    // Creating the file here would break Pi's lazy-flush mechanism
    // (Pi uses openSync with 'wx' flag which fails if file exists).
    if (!existsSync(sessionPath)) {
      return true
    }

    const entry = JSON.stringify({
      type: 'session_info',
      name,
    })
    appendFileSync(sessionPath, entry + '\n')
    return true
  } catch {
    return false
  }
}

export function deleteSession(sessionPath: string, sessionDir?: string): boolean {
  if (!existsSync(sessionPath)) return false

  try {
    unlinkSync(sessionPath)

    const dir = dirname(sessionPath)
    const remaining = readdirSync(dir).filter((name) => name.endsWith('.jsonl'))
    if (remaining.length === 0) {
      rmSync(dir, { recursive: true })
    }

    return true
  } catch {
    return false
  }
}

export function addForkPoint(sessionPath: string, entryId: string, childName: string): boolean {
  if (!existsSync(sessionPath)) return false

  try {
    const entry = JSON.stringify({
      type: 'fork_point',
      entryId,
      childName,
    })
    appendFileSync(sessionPath, entry + '\n')
    return true
  } catch {
    return false
  }
}

export function setSessionStatus(sessionPath: string, status: 'active' | 'completed'): boolean {
  if (!existsSync(sessionPath)) return false

  try {
    const entry = JSON.stringify({
      type: 'session_info',
      status,
    })
    appendFileSync(sessionPath, entry + '\n')
    return true
  } catch {
    return false
  }
}

export function getForkPoints(sessionPath: string): ForkPoint[] {
  if (!existsSync(sessionPath)) return []

  const forkPoints: ForkPoint[] = []

  try {
    const content = readFileSync(sessionPath, 'utf-8')
    const lines = content.split('\n').filter((line) => line.trim().length > 0)

    for (let i = 1; i < lines.length; i++) {
      try {
        const entry = JSON.parse(lines[i]) as Record<string, unknown>
        if (entry.type === 'fork_point' && typeof entry.entryId === 'string') {
          forkPoints.push({
            entryId: entry.entryId,
            childName: typeof entry.childName === 'string' ? entry.childName : '',
          })
        }
      } catch {
        continue
      }
    }
  } catch {
    return []
  }

  return forkPoints
}

import { useState, useEffect, useCallback, useRef } from 'react'
import type { ChatMessage, ContentBlock, ToolCallBlock } from '../types/message'
import type {
  AgentSessionEvent,
  MessageUpdateEvent,
  ToolExecutionEndEvent,
  PiImageContent,
  PiUserMessage,
  PiAssistantMessage,
  PiToolResultMessage,
  PiContentBlock,
} from '../types/pi-events'
import type { ForkPoint } from '../types/session'

export interface TokenUsage {
  inputTokens: number
  outputTokens: number
  cacheReadTokens: number
  cacheWriteTokens: number
  totalTokens: number
  totalCost: number
  contextWindowSize: number
}

function inferContextWindow(model: string): number {
  if (!model) return 200000
  const m = model.toLowerCase()
  if (m.includes('gpt-4o') || m.includes('gpt-4-turbo')) return 128000
  if (m.includes('claude')) return 200000
  return 200000
}

interface UsePiRpcReturn {
  messages: ChatMessage[]
  isConnected: boolean
  isStreaming: boolean
  streamingMessageId: string | null
  sendPrompt: (text: string, images?: { data: string; mimeType: string }[]) => void
  abort: () => void
  pendingUiRequests: Array<{ id: string; method: string; [key: string]: unknown }>
  respondToUiRequest: (requestId: string, response: Record<string, unknown>) => void
  clearMessages: () => void
  loadHistory: () => Promise<void>
  forkPoints: ForkPoint[]
  loadForkPoints: (sessionPath: string) => Promise<void>
  onAgentEnd: (() => void) | null
  setOnAgentEnd: (cb: (() => void) | null) => void
  tokenUsage: TokenUsage
}

export function usePiRpc(): UsePiRpcReturn {
  const [messages, setMessages] = useState<ChatMessage[]>([])
  const [isConnected, setIsConnected] = useState(false)
  const [isStreaming, setIsStreaming] = useState(false)
  const [pendingUiRequests, setPendingUiRequests] = useState<Array<{ id: string; method: string; [key: string]: unknown }>>([])
  const [tokenUsage, setTokenUsage] = useState<TokenUsage>({
    inputTokens: 0,
    outputTokens: 0,
    cacheReadTokens: 0,
    cacheWriteTokens: 0,
    totalTokens: 0,
    totalCost: 0,
    contextWindowSize: 200000,
  })

  const currentAssistantId = useRef<string | null>(null)
  const currentContentBlocks = useRef<Map<number, ContentBlock>>(new Map())
  const toolCallArgsBuffer = useRef<Map<number, string>>(new Map())
  const pendingToolCallArgs = useRef<Map<string, Record<string, unknown>>>(new Map())
  const countedResponseIds = useRef<Set<string>>(new Set())

  const updateContentBlock = useCallback(
    (contentIndex: number, updater: (block: ContentBlock) => ContentBlock) => {
      const existing = currentContentBlocks.current.get(contentIndex)
      if (existing) {
        currentContentBlocks.current.set(contentIndex, updater(existing))
      }
    },
    [],
  )

  // RAF-throttled sync to avoid flickering on every text_delta
  const rafIdRef = useRef<number | null>(null)
  const syncContentBlocksToMessage = useCallback(() => {
    if (!currentAssistantId.current) return
    // Always schedule at most one RAF frame
    if (rafIdRef.current !== null) return
    rafIdRef.current = requestAnimationFrame(() => {
      rafIdRef.current = null
      if (!currentAssistantId.current) return
      const blocks = Array.from(currentContentBlocks.current.values())
      const assistantId = currentAssistantId.current
      setMessages((prev) =>
        prev.map((msg) => {
          if (msg.id !== assistantId) return msg
          return { ...msg, blocks: [...blocks] }
        }),
      )
    })
  }, [])

  // Force-flush any pending RAF sync (used at message/agent end)
  const flushSync = useCallback(() => {
    if (rafIdRef.current !== null) {
      cancelAnimationFrame(rafIdRef.current)
      rafIdRef.current = null
    }
    if (!currentAssistantId.current) return
    const blocks = Array.from(currentContentBlocks.current.values())
    const assistantId = currentAssistantId.current
    setMessages((prev) =>
      prev.map((msg) => {
        if (msg.id !== assistantId) return msg
        return { ...msg, blocks: [...blocks] }
      }),
    )
  }, [])

  const finalizeCurrentAssistant = useCallback(() => {
    if (!currentAssistantId.current) return
    flushSync()
  }, [flushSync])

  const handleEvent = useCallback(
    (event: AgentSessionEvent) => {
      switch (event.type) {
        case 'agent_start':
          setIsStreaming(true)
          break

        case 'agent_end':
          setIsStreaming(false)
          flushSync()
          currentAssistantId.current = null
          currentContentBlocks.current.clear()
          toolCallArgsBuffer.current.clear()
          onAgentEndRef.current?.()
          break

        case 'message_start': {
          const msg = event.message
          if (msg.role === 'user') {
            const userMsg = msg as PiUserMessage
            const userContent =
              typeof userMsg.content === 'string'
                ? userMsg.content
                : userMsg.content
                    .filter((c): c is { type: 'text'; text: string } => c.type === 'text')
                    .map((c) => c.text)
                    .join('')

            const userChatMsg: ChatMessage = {
              id: crypto.randomUUID(),
              role: 'user',
              blocks: [{ type: 'text', content: userContent }],
              timestamp: userMsg.timestamp,
            }
            setMessages((prev) => [...prev, userChatMsg])
          } else if (msg.role === 'assistant') {
            const assistantMsg = msg as PiAssistantMessage
            const assistantId = crypto.randomUUID()
            currentAssistantId.current = assistantId
            currentContentBlocks.current.clear()
            toolCallArgsBuffer.current.clear()

            const chatMsg: ChatMessage = {
              id: assistantId,
              role: 'assistant',
              blocks: [],
              timestamp: assistantMsg.timestamp,
            }
            setMessages((prev) => [...prev, chatMsg])
          }
          break
        }

        case 'message_update': {
          const updateEvent = event as MessageUpdateEvent
          const ame = updateEvent.assistantMessageEvent

          if (!currentAssistantId.current) break

          switch (ame.type) {
            case 'text_start':
              currentContentBlocks.current.set(ame.contentIndex, { type: 'text', content: '' })
              break

            case 'text_delta':
              updateContentBlock(ame.contentIndex, (block) => {
                if (block.type === 'text') {
                  return { ...block, content: block.content + ame.delta }
                }
                return block
              })
              break

            case 'text_end':
              updateContentBlock(ame.contentIndex, (block) => {
                if (block.type === 'text') {
                  return { ...block, content: ame.content }
                }
                return block
              })
              break

            case 'thinking_start':
              currentContentBlocks.current.set(ame.contentIndex, { type: 'text', content: '', subtype: 'thinking' })
              break

            case 'thinking_delta':
              updateContentBlock(ame.contentIndex, (block) => {
                if (block.type === 'text') {
                  return { ...block, content: block.content + ame.delta, subtype: block.subtype }
                }
                return block
              })
              break

            case 'thinking_end':
              updateContentBlock(ame.contentIndex, (block) => {
                if (block.type === 'text') {
                  return { ...block, content: ame.content, subtype: block.subtype }
                }
                return block
              })
              break

            case 'toolcall_start':
              currentContentBlocks.current.set(ame.contentIndex, {
                type: 'tool_call',
                toolName: '',
                args: {},
                status: 'running',
              })
              toolCallArgsBuffer.current.set(ame.contentIndex, '')
              break

            case 'toolcall_delta': {
              const existing = toolCallArgsBuffer.current.get(ame.contentIndex) ?? ''
              toolCallArgsBuffer.current.set(ame.contentIndex, existing + ame.delta)
              break
            }

            case 'toolcall_end': {
              const argsStr = toolCallArgsBuffer.current.get(ame.contentIndex) ?? '{}'
              let parsedArgs: Record<string, unknown>
              try {
                parsedArgs = JSON.parse(argsStr)
              } catch {
                parsedArgs = { _raw: argsStr }
              }
              currentContentBlocks.current.set(ame.contentIndex, {
                type: 'tool_call',
                toolName: ame.toolCall.name,
                args: parsedArgs,
                status: 'running',
              })
              pendingToolCallArgs.current.set(ame.toolCall.id, parsedArgs)
              toolCallArgsBuffer.current.delete(ame.contentIndex)
              // toolcall_end is an important structural change, flush immediately
              flushSync()
              break
            }

            case 'done': {
              const msg = ame.message
              if (msg.usage && msg.responseId && !countedResponseIds.current.has(msg.responseId)) {
                countedResponseIds.current.add(msg.responseId)
                setTokenUsage((prev) => ({
                  inputTokens: prev.inputTokens + msg.usage.input,
                  outputTokens: prev.outputTokens + msg.usage.output,
                  cacheReadTokens: prev.cacheReadTokens + msg.usage.cacheRead,
                  cacheWriteTokens: prev.cacheWriteTokens + msg.usage.cacheWrite,
                  totalTokens: msg.usage.totalTokens,
                  totalCost: prev.totalCost + msg.usage.cost.total,
                  contextWindowSize: inferContextWindow(msg.responseModel),
                }))
              } else if (msg.usage) {
                setTokenUsage((prev) => ({
                  ...prev,
                  contextWindowSize: inferContextWindow(msg.responseModel),
                }))
              }
              break
            }
            case 'error':
              break
          }

          if (ame.type !== 'toolcall_end') {
            syncContentBlocksToMessage()
          }
          break
        }

        case 'message_end': {
          const msg = event.message
          // toolResult messages are now handled in tool_execution_end
          // to avoid duplicate rendering.
          if (msg.role === 'assistant') {
            const assistantMsg = msg as PiAssistantMessage
            if (assistantMsg.usage && assistantMsg.responseId && !countedResponseIds.current.has(assistantMsg.responseId)) {
              countedResponseIds.current.add(assistantMsg.responseId)
              setTokenUsage((prev) => ({
                inputTokens: prev.inputTokens + assistantMsg.usage.input,
                outputTokens: prev.outputTokens + assistantMsg.usage.output,
                cacheReadTokens: prev.cacheReadTokens + assistantMsg.usage.cacheRead,
                cacheWriteTokens: prev.cacheWriteTokens + assistantMsg.usage.cacheWrite,
                totalTokens: assistantMsg.usage.totalTokens,
                totalCost: prev.totalCost + assistantMsg.usage.cost.total,
                contextWindowSize: inferContextWindow(assistantMsg.responseModel),
              }))
            } else if (assistantMsg.usage) {
              setTokenUsage((prev) => ({
                ...prev,
                contextWindowSize: inferContextWindow(assistantMsg.responseModel),
              }))
            }
          }
          break
        }

        case 'tool_execution_start':
          setMessages((prev) =>
            prev.map((msg) => {
              if (msg.id !== currentAssistantId.current) return msg
              return {
                ...msg,
                blocks: msg.blocks.map((block) => {
                  if (
                    block.type === 'tool_call' &&
                    block.toolName === event.toolName &&
                    block.status === 'pending'
                  ) {
                    return { ...block, status: 'running' as const }
                  }
                  return block
                }),
              }
            }),
          )
          break

        case 'tool_execution_end': {
          const toolEvent = event as ToolExecutionEndEvent
          const toolArgs = pendingToolCallArgs.current.get(toolEvent.toolCallId)
          pendingToolCallArgs.current.delete(toolEvent.toolCallId)

          const resultBlocks: ContentBlock[] = []

          // Collect tool output content
          if (toolEvent.result?.content) {
            for (const c of toolEvent.result.content as Array<Record<string, unknown>>) {
              if (c.type === 'text' && typeof c.text === 'string') {
                resultBlocks.push({ type: 'text', content: c.text })
              } else if (c.type === 'image') {
                const img = c as unknown as PiImageContent
                resultBlocks.push({
                  type: 'image',
                  src: `data:${img.mimeType};base64,${img.data}`,
                  alt: `Result from ${toolEvent.toolName}`,
                })
              }
            }
          }

          if (
            toolEvent.toolName === 'write' &&
            toolArgs &&
            typeof toolArgs.path === 'string' &&
            toolArgs.path.endsWith('.html') &&
            typeof toolArgs.content === 'string'
          ) {
            resultBlocks.push({
              type: 'html',
              content: toolArgs.content,
              title: toolArgs.path.split('/').pop(),
            })
          }

          // Build the tool_result block to append after tool_call
          const toolResultBlock: ContentBlock | null = resultBlocks.length > 0
            ? { type: 'tool_result', toolCallId: toolEvent.toolCallId, content: resultBlocks }
            : null

          setMessages((prev) =>
            prev.map((msg) => {
              if (msg.id !== currentAssistantId.current) return msg
              const updatedBlocks = [] as ContentBlock[]
              for (const block of msg.blocks) {
                if (block.type === 'tool_call' && block.status === 'running') {
                  updatedBlocks.push({ ...block, status: 'completed' as const })
                  // Insert tool_result right after its tool_call
                  if (toolResultBlock && (block as ToolCallBlock).toolName === toolEvent.toolName) {
                    updatedBlocks.push(toolResultBlock)
                  }
                } else {
                  updatedBlocks.push(block)
                }
              }
              return { ...msg, blocks: updatedBlocks }
            }),
          )
          break
        }

        default:
          break
      }
    },
    [updateContentBlock, syncContentBlocksToMessage, finalizeCurrentAssistant],
  )

  useEffect(() => {
    const cleanup = window.api.onStateChanged((state) => {
      setIsConnected(state.connected)
    })

    window.api.getState().then((state) => {
      setIsConnected(state.connected)
    })

    return cleanup
  }, [])

  useEffect(() => {
    const cleanup = window.api.onEvent((rawEvent) => {
      handleEvent(rawEvent as AgentSessionEvent)
    })
    return cleanup
  }, [handleEvent])

  useEffect(() => {
    const cleanup = window.api.onExtensionUiRequest((data) => {
      const req = data as { id: string; method: string; [key: string]: unknown }
      if (req.method === 'notify') {
        return
      }
      if (req.method === 'setStatus' || req.method === 'setWidget' || req.method === 'setTitle' || req.method === 'set_editor_text') {
        return
      }
      setPendingUiRequests(prev => [...prev, req])
    })
    return cleanup
  }, [])

  const respondToUiRequest = useCallback((requestId: string, response: Record<string, unknown>) => {
    window.api.sendExtensionUIResponse({ type: 'extension_ui_response', id: requestId, ...response })
    setPendingUiRequests(prev => prev.filter(r => r.id !== requestId))
  }, [])

  const sendPrompt = useCallback(
    (text: string, images?: { data: string; mimeType: string }[]) => {
      const command: Record<string, unknown> = {
        type: 'prompt',
        message: text,
        id: crypto.randomUUID(),
      }
      if (images && images.length > 0) {
        command.images = images.map((img) => ({
          type: 'image' as const,
          data: img.data,
          mimeType: img.mimeType,
        }))
      }
      window.api.sendCommand(command)
    },
    [],
  )

  const abort = useCallback(() => {
    window.api.sendCommand({ type: 'abort' })
  }, [])

  const clearMessages = useCallback(() => {
    setMessages([])
    setForkPoints([])
    setTokenUsage({
      inputTokens: 0,
      outputTokens: 0,
      cacheReadTokens: 0,
      cacheWriteTokens: 0,
      totalTokens: 0,
      totalCost: 0,
      contextWindowSize: 200000,
    })
    currentAssistantId.current = null
    currentContentBlocks.current.clear()
    toolCallArgsBuffer.current.clear()
    pendingToolCallArgs.current.clear()
    countedResponseIds.current.clear()
  }, [])

  const [forkPoints, setForkPoints] = useState<ForkPoint[]>([])
  const onAgentEndRef = useRef<(() => void) | null>(null)

  const setOnAgentEnd = useCallback((cb: (() => void) | null) => {
    onAgentEndRef.current = cb
  }, [])

  const loadForkPoints = useCallback(async (sessionPath: string) => {
    type ExtendedApiWithForkPoints = typeof window.api & { getForkPoints: (path: string) => Promise<ForkPoint[]> }
    const apiWithFp = window.api as ExtendedApiWithForkPoints
    try {
      const points = await apiWithFp.getForkPoints(sessionPath)
      setForkPoints(points)
    } catch {
      setForkPoints([])
    }
  }, [])

  const loadHistory = useCallback(async () => {
    type ExtendedApiWithMessages = typeof window.api & { getMessages: () => Promise<unknown[]> }
    const api = window.api as ExtendedApiWithMessages

    let piMessages: unknown[]
    try {
      piMessages = await api.getMessages()
    } catch {
      return
    }

    if (!Array.isArray(piMessages) || piMessages.length === 0) {
      clearMessages()
      return
    }

    const chatMessages: ChatMessage[] = []

    for (const raw of piMessages) {
      const msg = raw as Record<string, unknown>
      const piEntryId = typeof msg.id === 'string' ? msg.id : undefined
      if (msg.role === 'user') {
        const content = typeof msg.content === 'string'
          ? msg.content
          : Array.isArray(msg.content)
            ? (msg.content as PiContentBlock[])
                .filter((c): c is { type: 'text'; text: string } => c.type === 'text')
                .map((c) => c.text)
                .join('')
            : ''
        chatMessages.push({
          id: crypto.randomUUID(),
          role: 'user',
          blocks: [{ type: 'text', content }],
          timestamp: typeof msg.timestamp === 'number' ? msg.timestamp : Date.now(),
          piEntryId,
        })
      } else if (msg.role === 'assistant') {
        const blocks: ContentBlock[] = []
        const content = msg.content as PiContentBlock[]
        if (Array.isArray(content)) {
          for (const c of content) {
            if (c.type === 'text') {
              blocks.push({ type: 'text', content: c.text })
            } else if (c.type === 'thinking') {
              blocks.push({ type: 'text', content: c.thinking, subtype: 'thinking' })
            } else if (c.type === 'toolCall') {
              blocks.push({
                type: 'tool_call',
                toolName: c.name,
                args: c.arguments,
                status: 'completed',
              })
            }
          }
        }
        chatMessages.push({
          id: crypto.randomUUID(),
          role: 'assistant',
          blocks,
          timestamp: typeof msg.timestamp === 'number' ? msg.timestamp : Date.now(),
          piEntryId,
        })
      } else if (msg.role === 'toolResult') {
        const lastAssistant = chatMessages.findLast((m) => m.role === 'assistant')
        if (lastAssistant) {
          const content = msg.content as PiContentBlock[]
          const resultBlocks: ContentBlock[] = []
          if (Array.isArray(content)) {
            for (const c of content) {
              if (c.type === 'text') {
                resultBlocks.push({ type: 'text', content: c.text })
              } else if (c.type === 'image') {
                const img = c as PiImageContent
                resultBlocks.push({
                  type: 'image',
                  src: `data:${img.mimeType};base64,${img.data}`,
                  alt: `Result from ${msg.toolName as string}`,
                })
              }
            }
          }
          if (resultBlocks.length > 0) {
            lastAssistant.blocks.push({
              type: 'tool_result',
              toolCallId: msg.toolCallId as string || '',
              content: resultBlocks,
            })
          }
        }
      }
    }

    // Sum usage across all assistant messages (per-message, not cumulative)
    let restoredUsage: TokenUsage | null = null
    let lastResponseModel = ''
    for (const raw of piMessages) {
      const msg = raw as Record<string, unknown>
      if (msg.role === 'assistant') {
        const usage = msg.usage as { input: number; output: number; cacheRead: number; cacheWrite: number; totalTokens: number; cost: { input: number; output: number; cacheRead: number; cacheWrite: number; total: number } } | undefined
        if (typeof msg.responseModel === 'string') {
          lastResponseModel = msg.responseModel
        }
        if (usage) {
          if (!restoredUsage) {
            restoredUsage = {
              inputTokens: usage.input,
              outputTokens: usage.output,
              cacheReadTokens: usage.cacheRead,
              cacheWriteTokens: usage.cacheWrite,
              totalTokens: usage.totalTokens,
              totalCost: usage.cost.total,
              contextWindowSize: inferContextWindow(lastResponseModel),
            }
          } else {
            const newInput = restoredUsage.inputTokens + usage.input
            const newOutput = restoredUsage.outputTokens + usage.output
            const newCacheRead = restoredUsage.cacheReadTokens + usage.cacheRead
            const newCacheWrite = restoredUsage.cacheWriteTokens + usage.cacheWrite
            restoredUsage = {
              inputTokens: newInput,
              outputTokens: newOutput,
              cacheReadTokens: newCacheRead,
              cacheWriteTokens: newCacheWrite,
              totalTokens: usage.totalTokens,
              totalCost: restoredUsage.totalCost + usage.cost.total,
              contextWindowSize: inferContextWindow(lastResponseModel),
            }
          }
        }
      }
    }

    clearMessages()
    setMessages(chatMessages)
    for (const raw of piMessages) {
      const msg = raw as Record<string, unknown>
      if (msg.role === 'assistant' && typeof msg.responseId === 'string') {
        countedResponseIds.current.add(msg.responseId)
      }
    }
    if (restoredUsage) {
      setTokenUsage(restoredUsage)
    }
  }, [clearMessages])

  const streamingMessageId = isStreaming ? currentAssistantId.current : null

  return { messages, isConnected, isStreaming, streamingMessageId, sendPrompt, abort, pendingUiRequests, respondToUiRequest, clearMessages, loadHistory, forkPoints, loadForkPoints, onAgentEnd: onAgentEndRef.current, setOnAgentEnd, tokenUsage }
}

import type { AgentSession, AgentSessionEvent, AgentSessionRuntime } from '@earendil-works/pi-coding-agent'

process.on('uncaughtException', (err: Error) => {
  process.parentPort?.postMessage({ channel: 'error', error: `Uncaught: ${err.message}` })
})

process.on('unhandledRejection', (reason: unknown) => {
  const msg = reason instanceof Error ? reason.message : String(reason)
  process.parentPort?.postMessage({ channel: 'error', error: `Unhandled rejection: ${msg}` })
})

interface WorkerInit {
  cwd: string
  sessionPath?: string
}

interface WorkerCommand {
  id?: string
  type: string
  [key: string]: unknown
}

let session: AgentSession | null = null
let runtime: AgentSessionRuntime | null = null
let sessionManager: import('@earendil-works/pi-coding-agent').SessionManager | null = null
let unsubscribe: (() => void) | null = null
let pi: typeof import('@earendil-works/pi-coding-agent') | null = null

function send(msg: Record<string, unknown>): void {
  process.parentPort?.postMessage(msg)
}

function forwardEvent(event: AgentSessionEvent): void {
  send({ channel: 'event', data: event })
}

async function bindSession(): Promise<void> {
  unsubscribe?.()
  if (!session) return

  await session.bindExtensions({})

  unsubscribe = session.subscribe((event) => {
    forwardEvent(event)

    if (event.type === 'agent_end') {
      send({ channel: 'agent_end' })
    }
  })
}

async function init(data: WorkerInit): Promise<void> {
  pi = await import('@earendil-works/pi-coding-agent')
  const agentDir = pi.getAgentDir()

  const createRuntime: pi.CreateAgentSessionRuntimeFactory = async ({ cwd, sessionManager: sm, sessionStartEvent }) => {
    sessionManager = sm
    const services = await pi!.createAgentSessionServices({ cwd, agentDir })
    return {
      ...(await pi!.createAgentSessionFromServices({
        services,
        sessionManager: sm,
        sessionStartEvent,
      })),
      services,
      diagnostics: services.diagnostics,
    }
  }

  let sm: pi.SessionManager
  if (data.sessionPath) {
    sm = pi.SessionManager.open(data.sessionPath)
  } else {
    sm = pi.SessionManager.continueRecent(data.cwd)
  }

  runtime = await pi.createAgentSessionRuntime(createRuntime, {
    cwd: data.cwd,
    agentDir,
    sessionManager: sm,
  })

  session = runtime.session
  await bindSession()

  send({ channel: 'connected', data: { sessionFile: session.sessionFile, sessionId: session.sessionId } })
}

async function handleCommand(cmd: WorkerCommand): Promise<void> {
  if (!session || !runtime || !pi) {
    send({ channel: 'response', id: cmd.id, success: false, error: 'Session not initialized' })
    return
  }

  try {
    switch (cmd.type) {
      case 'prompt': {
        await session.prompt(cmd.message as string, {
          images: cmd.images as pi.ImageContent[] | undefined,
          streamingBehavior: cmd.streamingBehavior as 'steer' | 'followUp' | undefined,
        })
        send({ channel: 'response', id: cmd.id, command: 'prompt', success: true })
        break
      }

      case 'steer': {
        await session.steer(cmd.message as string, cmd.images as pi.ImageContent[] | undefined)
        send({ channel: 'response', id: cmd.id, command: 'steer', success: true })
        break
      }

      case 'follow_up': {
        await session.followUp(cmd.message as string, cmd.images as pi.ImageContent[] | undefined)
        send({ channel: 'response', id: cmd.id, command: 'follow_up', success: true })
        break
      }

      case 'abort': {
        await session.abort()
        send({ channel: 'response', id: cmd.id, command: 'abort', success: true })
        break
      }

      case 'get_state': {
        send({
          channel: 'response',
          id: cmd.id,
          command: 'get_state',
          success: true,
          data: {
            sessionFile: session.sessionFile,
            sessionId: session.sessionId,
            sessionName: session.sessionName,
            isStreaming: session.isStreaming,
            isCompacting: session.isCompacting,
            thinkingLevel: session.thinkingLevel,
            messageCount: session.messages.length,
          },
        })
        break
      }

      case 'get_messages': {
        let messages = session.messages
        if (messages.length === 0 && sessionManager) {
          try {
            const entries = sessionManager.getEntries()
            const messageEntries = entries.filter((e) => e.type === 'message' && (e as Record<string, unknown>).message)
            messages = messageEntries.map((e) => {
              const entry = e as Record<string, unknown>
              const msg = { ...(entry.message as Record<string, unknown>) }
              if (!msg.id && typeof entry.id === 'string') {
                msg.id = entry.id
              }
              return msg
            }) as unknown as AgentSession['messages']
          } catch {
            // getEntries failed вҖ” return empty messages
          }
        }
        send({
          channel: 'response',
          id: cmd.id,
          command: 'get_messages',
          success: true,
          data: { messages },
        })
        break
      }

      case 'get_fork_messages': {
        const messages = session.getUserMessagesForForking()
        send({
          channel: 'response',
          id: cmd.id,
          command: 'get_fork_messages',
          success: true,
          data: { messages },
        })
        break
      }

      case 'set_session_name': {
        session.setSessionName(cmd.name as string)
        send({ channel: 'response', id: cmd.id, command: 'set_session_name', success: true })
        break
      }

      case 'new_session': {
        const result = await runtime.newSession({
          parentSession: cmd.parentSession as string | undefined,
        })
        if (!result.cancelled) {
          session = runtime.session
          await bindSession()
        }
        send({ channel: 'response', id: cmd.id, command: 'new_session', success: true, data: result })
        break
      }

      case 'switch_session': {
        const result = await runtime.switchSession(cmd.sessionPath as string)
        if (!result.cancelled) {
          session = runtime.session
          await bindSession()
        }
        send({ channel: 'response', id: cmd.id, command: 'switch_session', success: true, data: result })
        break
      }

      case 'fork': {
        const result = await runtime.fork(cmd.entryId as string)
        if (!result.cancelled) {
          session = runtime.session
          await bindSession()
        }
        send({ channel: 'response', id: cmd.id, command: 'fork', success: true, data: { text: result.selectedText ?? '', cancelled: result.cancelled } })
        break
      }

      case 'compact': {
        const result = await session.compact(cmd.customInstructions as string | undefined)
        send({ channel: 'response', id: cmd.id, command: 'compact', success: true, data: result })
        break
      }

      case 'send_extension_ui_response': {
        send({ channel: 'response', id: cmd.id, command: 'send_extension_ui_response', success: true })
        break
      }

      case 'flush_session': {
        // Force-write the session file to disk and mark flushed.
        // This mirrors what createBranchedSession does when it has assistant messages:
        //   this._rewriteFile(); this.flushed = true;
        // Without this, newSession() never writes the file (flushed=false),
        // so the sidebar can't see the new session until the first assistant response.
        if (sessionManager) {
          // eslint-disable-next-line @typescript-eslint/no-explicit-any
          ;(sessionManager as any)._rewriteFile()
          // eslint-disable-next-line @typescript-eslint/no-explicit-any
          ;(sessionManager as any).flushed = true
        }
        send({ channel: 'response', id: cmd.id, command: 'flush_session', success: true })
        break
      }

      default:
        send({ channel: 'response', id: cmd.id, command: cmd.type, success: false, error: `Unknown command: ${cmd.type}` })
    }
  } catch (err: unknown) {
    send({
      channel: 'response',
      id: cmd.id,
      command: cmd.type,
      success: false,
      error: err instanceof Error ? err.message : String(err),
    })
  }
}

process.parentPort.on('message', (event: Electron.ParentPortMessageEvent) => {
  const msg = event.data as WorkerCommand | { type: 'init'; data: WorkerInit }
  if (msg.type === 'init') {
    init((msg as { data: WorkerInit }).data).catch((err: Error) => {
      console.error('[PiWorker] Init failed:', err.message)
      console.error('[PiWorker] Stack:', err.stack)
      send({ channel: 'error', error: `Init failed: ${err.message}` })
    })
    return
  }

  handleCommand(msg as WorkerCommand).catch((err: Error) => {
    send({ channel: 'error', error: err.message })
  })
})

import { app, BrowserWindow, ipcMain, nativeTheme } from 'electron'
