// Track which session Pi is currently connected to
const [piConnectedPath, setPiConnectedPath] = useState<string | null>(null)

// Determine what messages/tokenUsage/forkPoints to show
// When lazy-switched (displayed !== Pi-connected), use cache; otherwise use usePiRpc state
const isLazySwitched = sessionCache.displayedSessionPath !== null && sessionCache.displayedSessionPath !== piConnectedPath
const displayedMessages = isLazySwitched ? sessionCache.displayedMessages : messages
const displayedTokenUsage = isLazySwitched ? sessionCache.displayedTokenUsage : tokenUsage
const displayedForkPoints = isLazySwitched ? sessionCache.displayedForkPoints : forkPoints
const displayedStreaming = isLazySwitched ? sessionCache.isDisplayedStreaming : isStreaming
const displayedStreamingId = isLazySwitched ? (sessionCache.getCache(sessionCache.displayedSessionPath!)?.streamingMessageId ?? null) : streamingMessageId

const [viewMode, setViewMode] = useState<ViewMode>(() => {
  const saved = localStorage.getItem('xi-view-mode') as ViewMode
  return saved === 'normal' || saved === 'turn' || saved === 'outline' ? saved : 'normal'
})

// The "active session" for display purposes (title bar, etc.)
const activeSessionPath = isLazySwitched ? sessionCache.displayedSessionPath : (currentSession?.filePath ?? null)
const activeSession = activeSessionPath
  ? sessions?.projects?.flatMap(p => p.allSessions).find(s => s.filePath === activeSessionPath)
  : currentSession

const activeSessionName = activeSession ? getDisplayName(activeSession) : null

// Background streaming session name (for SoftSwitchBanner)
const backgroundSessionName = (() => {
  if (!isLazySwitched || !piConnectedPath) return null
  const bgSession = sessions?.projects?.flatMap(p => p.allSessions).find(s => s.filePath === piConnectedPath)
  return bgSession ? getDisplayName(bgSession) : null
})()

