const handleSwitchSession = useCallback(async (sessionPath: string) => {
  // Lazy Switch logic:
  // - If Pi is streaming, switch display only (don't touch Pi connection)
  // - If Pi is idle, switch display immediately + switch Pi in background
  if (isStreaming && piConnectedPath !== sessionPath) {
    // Soft switch: just change what we display
    await sessionCache.displaySession(sessionPath)
    return
  }

  // Hard switch (Pi idle, or clicking the same session)
  if (piConnectedPath === sessionPath) return

  const prevPath = piConnectedPath
  setPiConnectedPath(sessionPath)
  await sessionCache.displaySession(sessionPath)

  const result = await switchSession(sessionPath)
  if (result.success) {
    sessionCache.setPiConnectedSessionPath(sessionPath)
    clearMessages()
    await loadHistory()
    await loadForkPoints(sessionPath)
    await refresh()
  } else {
    setPiConnectedPath(prevPath)
    await sessionCache.displaySession(prevPath ?? '')
  }
}, [isStreaming, piConnectedPath, switchSession, clearMessages, loadHistory, loadForkPoints, refresh, sessionCache])

