const handleNewSession = useCallback(async (name: string, parentSessionPath: string) => {
  if (isStreaming) {
    // Abort background streaming before creating new session
    abort()
  }
  clearMessages()
  const result = await newSession(name, parentSessionPath)
  if (result) {
    await refresh()
    // After newSession, Pi is connected to the new session
    setPiConnectedPath(currentSession?.filePath ?? null)
    sessionCache.setPiConnectedSessionPath(currentSession?.filePath ?? null)
  }
}, [isStreaming, abort, clearMessages, newSession, refresh, currentSession, sessionCache])

const handleForkAtEntry = useCallback(async (entryId: string, name: string) => {
  if (isStreaming) {
    abort()
  }
  clearMessages()
  await forkAtEntry(entryId, name)
  await loadHistory()
  await refresh()
  setPiConnectedPath(currentSession?.filePath ?? null)
  sessionCache.setPiConnectedSessionPath(currentSession?.filePath ?? null)
}, [isStreaming, abort, clearMessages, forkAtEntry, loadHistory, refresh, currentSession, sessionCache])

const handleForkFromEnd = useCallback(async (sessionPath: string, name: string) => {
  if (isStreaming) {
    abort()
  }
  const msgs = await getForkMessages()
  const lastEntry = msgs[msgs.length - 1]
  if (!lastEntry?.entryId) return
  clearMessages()
  await forkAtEntry(lastEntry.entryId, name)
  await loadHistory()
  await refresh()
  setPiConnectedPath(currentSession?.filePath ?? null)
  sessionCache.setPiConnectedSessionPath(currentSession?.filePath ?? null)
}, [isStreaming, abort, getForkMessages, clearMessages, forkAtEntry, loadHistory, refresh, currentSession, sessionCache])

const handleClearSession = useCallback(async () => {
  if (isStreaming) {
    abort()
  }
  clearMessages()
  const ok = await clearSession()
  if (ok) {
    clearMessages()
    await loadHistory()
    await refresh()
    setPiConnectedPath(currentSession?.filePath ?? null)
    sessionCache.setPiConnectedSessionPath(currentSession?.filePath ?? null)
  }
}, [isStreaming, abort, clearMessages, clearSession, loadHistory, refresh, currentSession, sessionCache])

