  await loadHistory()
  await refresh()
  setPiConnectedPath(currentSessionRef.current?.filePath ?? null)
  setPiConnectedSessionPath(currentSessionRef.current?.filePath ?? null)
}, [isStreaming, abort, clearMessages, forkAtEntry, loadHistory, refresh, setPiConnectedSessionPath])

const handleForkFromEnd = useCallback(async (sessionPath: string, name: string) => {
  if (isStreaming) {
    abort()
  }
  const msgs = await getForkMessages()
