    syncDisplayedFromCache(displayedSessionPathRef.current)
  }, [syncDisplayedFromCache])

  return {
    displayedSessionPath,
    piConnectedSessionPath,
    displayedMessages,
    isReadOnly,
    isDisplayedStreaming,
    displayedTokenUsage,
    displayedForkPoints,
    getCache,
    getOrCreateCache,
    updateCache,
    displaySession,
    setPiConnectedSessionPath,
    clearCache,
    setCacheStreaming,
    refreshDisplayedMessages,
  }
}
